    ProductionLogger.logDatabaseOperation('INSERT', table, data, null, duration);
  }

  static void logUpdate(String table, Map<String, dynamic> data, String? whereClause, Duration? duration) {
    ProductionLogger.logDatabaseOperation('UPDATE', table, data, null, duration);
  }

  static void logDelete(String table, String? whereClause, Duration? duration) {
    ProductionLogger.logDatabaseOperation('DELETE', table, null, null, duration);
  }

  static void logSelect(String table, String? whereClause, Duration? duration) {
    ProductionLogger.logDatabaseOperation('SELECT', table, null, null, duration);
